insert into public.questions (id, topic, source, q, opts, ans_idx, exp, category, category_icon, is_active)
values
(5652, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Blood is composed of plasma and formed elements, with plasma making up approximately what percentage of total blood volume?', '["25%", "45%", "55%", "80%"]'::jsonb, 2, 'Plasma makes up approximately 55% of total blood volume, with formed elements (cells) comprising the remaining 45% (the haematocrit).', 'Pre-Council', '🎓', true),
(5653, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The most abundant plasma protein is:', '["Globulin", "Albumin", "Fibrinogen", "Prothrombin"]'::jsonb, 1, 'Albumin is the most abundant plasma protein, primarily responsible for maintaining plasma oncotic (colloid osmotic) pressure.', 'Pre-Council', '🎓', true),
(5654, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Albumin''s primary physiological function in blood is to:', '["Transport oxygen", "Maintain colloid osmotic pressure and transport substances", "Form blood clots", "Fight infection"]'::jsonb, 1, 'Albumin maintains the oncotic pressure that keeps fluid within the vascular space and also transports hormones, drugs, and other substances.', 'Pre-Council', '🎓', true),
(5655, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Which plasma protein is essential for blood clot formation?', '["Albumin", "Fibrinogen", "Alpha-globulin", "Transferrin"]'::jsonb, 1, 'Fibrinogen is converted to fibrin during the coagulation cascade, forming the structural mesh of a blood clot.', 'Pre-Council', '🎓', true),
(5656, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Globulins in plasma include which important immune-related proteins?', '["Antibodies (immunoglobulins)", "Clotting factors only", "Haemoglobin", "Electrolytes"]'::jsonb, 0, 'Gamma globulins include antibodies (immunoglobulins) essential for humoral immunity.', 'Pre-Council', '🎓', true),
(5657, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The normal haematocrit (packed cell volume) for an adult male is approximately:', '["20-25%", "40-50%", "60-70%", "80-90%"]'::jsonb, 1, 'Normal haematocrit is approximately 40-50% in adult males and slightly lower (36-46%) in adult females.', 'Pre-Council', '🎓', true),
(5658, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Erythrocytes (red blood cells) make up the majority of formed elements in blood and function primarily to:', '["Fight infection", "Transport oxygen and carbon dioxide", "Form clots", "Produce antibodies"]'::jsonb, 1, 'Erythrocytes contain haemoglobin, which binds and transports oxygen from the lungs to tissues and assists in CO2 transport.', 'Pre-Council', '🎓', true),
(5659, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Mature red blood cells lack a nucleus, which:', '["Prevents them from carrying oxygen", "Maximises internal space for haemoglobin", "Shortens their lifespan to hours", "Prevents deformability"]'::jsonb, 1, 'The absence of a nucleus in mature erythrocytes maximises the space available for haemoglobin, increasing oxygen-carrying capacity, though it also means they cannot divide or repair themselves.', 'Pre-Council', '🎓', true),
(5660, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The average lifespan of a red blood cell is approximately:', '["10 days", "40 days", "120 days", "300 days"]'::jsonb, 2, 'Red blood cells circulate for approximately 120 days before being removed by the spleen and liver.', 'Pre-Council', '🎓', true),
(5661, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Leukocytes (white blood cells) function primarily to:', '["Transport oxygen", "Provide immune defence against pathogens", "Form platelet plugs", "Maintain oncotic pressure"]'::jsonb, 1, 'White blood cells are the primary cellular component of the immune system, defending against infection and foreign substances.', 'Pre-Council', '🎓', true),
(5662, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Which type of white blood cell is the most abundant in a normal differential count?', '["Lymphocytes", "Neutrophils", "Eosinophils", "Basophils"]'::jsonb, 1, 'Neutrophils typically make up 50-70% of circulating white blood cells and are the first responders to acute bacterial infection.', 'Pre-Council', '🎓', true),
(5663, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Which white blood cell type increases characteristically in allergic reactions and parasitic infections?', '["Neutrophils", "Eosinophils", "Monocytes", "Basophils"]'::jsonb, 1, 'Eosinophils increase in response to allergic reactions and parasitic (especially helminthic) infections.', 'Pre-Council', '🎓', true),
(5664, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Which white blood cell releases histamine and is involved in allergic and inflammatory responses?', '["Basophils", "Neutrophils", "Lymphocytes", "Monocytes"]'::jsonb, 0, 'Basophils contain granules with histamine and heparin and play a role in allergic and inflammatory responses.', 'Pre-Council', '🎓', true),
(5665, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Monocytes, once they migrate into tissue, differentiate into:', '["Neutrophils", "Macrophages", "Lymphocytes", "Platelets"]'::jsonb, 1, 'Monocytes that enter tissue mature into macrophages, which phagocytose pathogens and debris.', 'Pre-Council', '🎓', true),
(5666, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Lymphocytes are primarily responsible for:', '["Phagocytosis of bacteria", "Adaptive immune responses, including antibody production and cell-mediated immunity", "Oxygen transport", "Blood clotting"]'::jsonb, 1, 'B and T lymphocytes mediate adaptive (specific) immunity, including antibody production (B cells) and direct cell killing/regulation (T cells).', 'Pre-Council', '🎓', true),
(5667, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Platelets (thrombocytes) function primarily to:', '["Transport oxygen", "Initiate blood clotting by forming a platelet plug", "Fight bacterial infection", "Produce antibodies"]'::jsonb, 1, 'Platelets adhere to sites of vessel injury and aggregate to form a platelet plug, the first step in haemostasis.', 'Pre-Council', '🎓', true),
(5668, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'A normal platelet count in adults is approximately:', '["10,000-50,000/microlitre", "150,000-450,000/microlitre", "1-5 million/microlitre", "500,000-1,000,000/microlitre only in illness"]'::jsonb, 1, 'Normal platelet count ranges from approximately 150,000 to 450,000 per microlitre of blood.', 'Pre-Council', '🎓', true),
(5669, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'A normal total white blood cell count in adults is approximately:', '["1,000-3,000/microlitre", "5,000-10,000/microlitre", "20,000-30,000/microlitre", "50,000-100,000/microlitre"]'::jsonb, 1, 'Normal adult WBC count is approximately 5,000-10,000 cells per microlitre; values outside this range suggest infection, inflammation, or haematological disorder.', 'Pre-Council', '🎓', true),
(5670, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Serum differs from plasma in that serum:', '["Contains fibrinogen and clotting factors", "Is plasma with fibrinogen and clotting factors removed after clotting", "Contains red blood cells", "Is identical to whole blood"]'::jsonb, 1, 'Serum is the fluid that remains after blood has clotted, meaning fibrinogen and other clotting factors have been consumed/removed, unlike plasma which retains them.', 'Pre-Council', '🎓', true),
(5671, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The process of blood cell formation is called:', '["Haemolysis", "Haematopoiesis", "Haemostasis", "Erythropoiesis only"]'::jsonb, 1, 'Haematopoiesis is the overall process by which all blood cell types are formed, primarily in the bone marrow in adults.', 'Pre-Council', '🎓', true),
(5672, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'In adults, the primary site of haematopoiesis is the:', '["Liver", "Spleen", "Red bone marrow", "Lymph nodes"]'::jsonb, 2, 'Red bone marrow, found in flat bones and the ends of long bones in adults, is the primary site of blood cell production.', 'Pre-Council', '🎓', true),
(5673, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'During fetal development, which organs serve as major sites of haematopoiesis before birth?', '["Lungs and kidneys", "Liver and spleen", "Skin and muscle", "Brain and heart"]'::jsonb, 1, 'The fetal liver and spleen are major haematopoietic sites before bone marrow haematopoiesis becomes dominant later in gestation and after birth.', 'Pre-Council', '🎓', true),
(5674, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Erythropoiesis (red blood cell production) is primarily stimulated by the hormone:', '["Thrombopoietin", "Erythropoietin", "Insulin", "Cortisol"]'::jsonb, 1, 'Erythropoietin, produced mainly by the kidneys in response to hypoxia, stimulates red blood cell production in bone marrow.', 'Pre-Council', '🎓', true),
(5675, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Erythropoietin is produced primarily by the:', '["Liver", "Kidneys", "Spleen", "Pancreas"]'::jsonb, 1, 'The kidneys are the primary source of erythropoietin, produced in response to tissue hypoxia, making renal disease a common cause of anaemia.', 'Pre-Council', '🎓', true),
(5676, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Which nutrient deficiency commonly causes microcytic (small cell) anaemia due to impaired haemoglobin synthesis?', '["Vitamin B12", "Iron", "Folate", "Vitamin C"]'::jsonb, 1, 'Iron is essential for haemoglobin synthesis; deficiency leads to microcytic, hypochromic anaemia.', 'Pre-Council', '🎓', true),
(5677, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Vitamin B12 and folate deficiency typically cause which type of anaemia?', '["Microcytic anaemia", "Macrocytic (megaloblastic) anaemia", "Normocytic anaemia only", "Haemolytic anaemia"]'::jsonb, 1, 'Both B12 and folate are essential for DNA synthesis during red cell maturation; deficiency causes large, immature red cells characteristic of megaloblastic anaemia.', 'Pre-Council', '🎓', true),
(5678, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Intrinsic factor, produced by gastric parietal cells, is essential for the absorption of:', '["Iron", "Vitamin B12", "Folate", "Vitamin C"]'::jsonb, 1, 'Intrinsic factor binds vitamin B12 in the stomach, enabling its absorption in the terminal ileum; its absence (e.g. after gastrectomy) causes pernicious anaemia.', 'Pre-Council', '🎓', true),
(5679, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Thrombopoietin primarily stimulates the production of:', '["Red blood cells", "White blood cells", "Platelets", "Plasma proteins"]'::jsonb, 2, 'Thrombopoietin, produced mainly by the liver, stimulates megakaryocyte development and platelet production in bone marrow.', 'Pre-Council', '🎓', true),
(5680, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Platelets are formed by the fragmentation of large bone marrow cells called:', '["Erythroblasts", "Megakaryocytes", "Myeloblasts", "Lymphoblasts"]'::jsonb, 1, 'Megakaryocytes are large bone marrow cells that shed cytoplasmic fragments to form circulating platelets.', 'Pre-Council', '🎓', true),
(5681, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Leukopoiesis refers to the production of:', '["Red blood cells", "White blood cells", "Platelets only", "Plasma"]'::jsonb, 1, 'Leukopoiesis is the formation of white blood cells (leukocytes) from bone marrow stem cells.', 'Pre-Council', '🎓', true),
(5682, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'All blood cells originate from a common precursor cell type known as:', '["A mature erythrocyte", "A pluripotent haematopoietic stem cell", "A lymphocyte", "A platelet"]'::jsonb, 1, 'All formed elements of blood arise from pluripotent haematopoietic stem cells in the bone marrow, which differentiate into the various myeloid and lymphoid cell lines.', 'Pre-Council', '🎓', true),
(5683, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Chronic kidney disease commonly causes anaemia primarily because of:', '["Excess iron absorption", "Reduced erythropoietin production", "Increased platelet destruction", "Increased white blood cell production"]'::jsonb, 1, 'Damaged kidneys produce less erythropoietin, reducing the stimulus for red blood cell production and causing anaemia of chronic kidney disease.', 'Pre-Council', '🎓', true),
(5684, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Aplastic anaemia results from:', '["Excess red blood cell production", "Bone marrow failure to produce adequate blood cells of all lineages", "Iron deficiency alone", "Excess platelet production"]'::jsonb, 1, 'Aplastic anaemia is characterised by bone marrow failure, leading to pancytopenia — reduced red cells, white cells, and platelets.', 'Pre-Council', '🎓', true),
(5685, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The ABO blood group system classifies blood based on the presence or absence of which substances on red blood cells?', '["Rh antigens", "A and B antigens", "Platelets", "Fibrinogen"]'::jsonb, 1, 'The ABO system is based on A and B antigens present (or absent) on the surface of red blood cells.', 'Pre-Council', '🎓', true),
(5686, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'A person with blood type A has which antigen(s) on their red blood cells and which antibody in their plasma?', '["A antigen; anti-B antibody", "B antigen; anti-A antibody", "No antigen; both antibodies", "Both antigens; no antibody"]'::jsonb, 0, 'Type A blood has the A antigen on red cells and naturally occurring anti-B antibodies in plasma.', 'Pre-Council', '🎓', true),
(5687, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'A person with blood type O has which antigens and antibodies?', '["No antigens; both anti-A and anti-B antibodies", "Both A and B antigens; no antibodies", "A antigen only; no antibodies", "B antigen only; anti-A antibody"]'::jsonb, 0, 'Type O blood has neither A nor B antigens on red cells, but plasma contains both anti-A and anti-B antibodies.', 'Pre-Council', '🎓', true),
(5688, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Which blood type is known as the ''universal donor'' for red cell transfusion?', '["AB positive", "O negative", "A positive", "B negative"]'::jsonb, 1, 'O negative red cells lack A, B, and Rh(D) antigens, making them least likely to trigger a transfusion reaction in recipients of any blood type — hence ''universal donor''.', 'Pre-Council', '🎓', true),
(5689, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Which blood type is known as the ''universal recipient''?', '["O negative", "AB positive", "A negative", "B positive"]'::jsonb, 1, 'AB positive individuals have both A and B antigens and the Rh(D) antigen already present, so they can theoretically receive red cells of any ABO/Rh type without triggering an ABO/Rh antibody reaction.', 'Pre-Council', '🎓', true),
(5690, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'An Rh-negative individual who receives Rh-positive blood may develop:', '["Immediate haemolysis with the first exposure", "Anti-Rh(D) antibodies, risking a reaction with future exposure to Rh-positive blood", "No immune response", "Immediate anaphylaxis only"]'::jsonb, 1, 'Rh-negative individuals typically develop anti-D antibodies only after exposure to Rh-positive blood; a severe reaction is more likely with subsequent exposures (sensitisation).', 'Pre-Council', '🎓', true),
(5691, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Rh incompatibility is of particular clinical concern in pregnancy when:', '["An Rh-positive mother carries an Rh-negative fetus", "An Rh-negative mother carries an Rh-positive fetus", "Both parents are Rh-negative", "The mother is blood type O"]'::jsonb, 1, 'An Rh-negative mother sensitised to Rh-positive fetal blood (often from a prior pregnancy) can develop antibodies that cross the placenta and cause haemolytic disease in a subsequent Rh-positive fetus.', 'Pre-Council', '🎓', true),
(5692, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Anti-D immunoglobulin is administered to Rh-negative mothers primarily to:', '["Treat existing haemolytic disease of the newborn", "Prevent maternal sensitisation to Rh-positive fetal blood", "Increase maternal red cell production", "Cure Rh incompatibility permanently"]'::jsonb, 1, 'Anti-D immunoglobulin is given prophylactically to prevent an Rh-negative mother''s immune system from forming antibodies against Rh-positive fetal cells.', 'Pre-Council', '🎓', true),
(5693, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Cross-matching before a blood transfusion is performed primarily to:', '["Determine the patient''s haemoglobin level", "Detect potential incompatibility between donor and recipient blood beyond basic ABO/Rh typing", "Measure platelet count", "Assess clotting time"]'::jsonb, 1, 'Cross-matching directly tests donor red cells against recipient serum (and vice versa) to detect antibody incompatibilities not captured by ABO/Rh typing alone.', 'Pre-Council', '🎓', true),
(5694, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'A major cross-match tests for reactions between:', '["Donor serum and recipient red cells", "Donor red cells and recipient serum", "Donor red cells and donor serum only", "Recipient red cells and recipient serum"]'::jsonb, 1, 'The major cross-match mixes donor red cells with recipient serum/plasma to check for antibodies in the recipient that would react against donor cells — the clinically critical test.', 'Pre-Council', '🎓', true),
(5695, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'An acute haemolytic transfusion reaction is most commonly caused by:', '["Bacterial contamination of blood", "ABO incompatibility due to clerical/identification error", "Allergic reaction to plasma proteins", "Volume overload"]'::jsonb, 1, 'The most common cause of acute haemolytic transfusion reactions is human error — administering ABO-incompatible blood due to misidentification.', 'Pre-Council', '🎓', true),
(5696, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Early signs of an acute haemolytic transfusion reaction include:', '["Improved oxygen saturation", "Fever, chills, back pain, and haemoglobinuria", "Decreased heart rate", "Improved urine output"]'::jsonb, 1, 'Fever, chills, flank/back pain, and dark urine (haemoglobinuria) from red cell destruction are classic early signs requiring immediate transfusion cessation.', 'Pre-Council', '🎓', true),
(5697, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'If a suspected transfusion reaction occurs, the immediate priority nursing action is to:', '["Slow the infusion rate", "Stop the transfusion immediately and maintain IV access with normal saline", "Administer antipyretics and continue the transfusion", "Increase the infusion rate to complete it quickly"]'::jsonb, 1, 'The transfusion must be stopped immediately at the first sign of a reaction, with the IV line kept open using normal saline while the reaction is assessed and reported.', 'Pre-Council', '🎓', true),
(5698, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Blood typing determines a person''s blood group by testing red blood cells with known:', '["Antibiotics", "Anti-A and anti-B antisera (reagents)", "Clotting factors", "Growth hormones"]'::jsonb, 1, 'Blood typing (forward typing) mixes red cells with known anti-A and anti-B antisera; agglutination patterns reveal the ABO group.', 'Pre-Council', '🎓', true),
(5699, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Agglutination during blood typing indicates:', '["Successful mixing with no reaction", "An antigen-antibody reaction, confirming presence of the corresponding antigen", "Blood contamination", "Normal haemoglobin levels"]'::jsonb, 1, 'Visible clumping (agglutination) occurs when the antisera''s antibodies bind matching antigens on the red cells, confirming which ABO antigens are present.', 'Pre-Council', '🎓', true),
(5700, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Before elective surgery likely to require transfusion, a ''type and screen'' is performed to:', '["Immediately cross-match all available blood units", "Determine ABO/Rh type and screen for unexpected antibodies in advance", "Replace the need for cross-matching entirely", "Measure haemoglobin only"]'::jsonb, 1, 'A type and screen establishes the patient''s blood type and checks for atypical antibodies ahead of time, speeding up cross-matching if transfusion becomes necessary.', 'Pre-Council', '🎓', true),
(5701, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Haemostasis refers to the physiological process that:', '["Causes red blood cell destruction", "Stops bleeding through vessel constriction, platelet plug formation, and coagulation", "Produces new blood cells", "Regulates blood pressure only"]'::jsonb, 1, 'Haemostasis is the sequence of events (vascular spasm, platelet plug formation, coagulation) that stops bleeding after vessel injury.', 'Pre-Council', '🎓', true),
(5702, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The first response to blood vessel injury in haemostasis is:', '["Coagulation cascade activation", "Vascular spasm (vasoconstriction)", "Platelet plug formation", "Fibrinolysis"]'::jsonb, 1, 'Immediate vasoconstriction of the injured vessel reduces blood flow and blood loss, the first step in haemostasis.', 'Pre-Council', '🎓', true),
(5703, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Platelet adhesion to an injured vessel wall is primarily mediated by:', '["Fibrinogen alone", "Von Willebrand factor binding platelets to exposed collagen", "Vitamin K", "Erythropoietin"]'::jsonb, 1, 'Von Willebrand factor acts as a bridge, binding platelets to exposed subendothelial collagen at the injury site, initiating platelet adhesion.', 'Pre-Council', '🎓', true),
(5704, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The coagulation cascade ultimately converts which protein into insoluble fibrin strands?', '["Albumin", "Fibrinogen", "Prothrombin directly", "Thrombin directly"]'::jsonb, 1, 'The cascade''s end point is thrombin converting soluble fibrinogen into insoluble fibrin, which forms the structural clot mesh.', 'Pre-Council', '🎓', true),
(5705, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Which clotting factor is also known as fibrinogen?', '["Factor I", "Factor II", "Factor VIII", "Factor X"]'::jsonb, 0, 'Factor I is fibrinogen; Factor II is prothrombin.', 'Pre-Council', '🎓', true),
(5706, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Which clotting factor is also known as prothrombin?', '["Factor I", "Factor II", "Factor V", "Factor IX"]'::jsonb, 1, 'Factor II is prothrombin, which thrombin (activated Factor II) converts fibrinogen into fibrin.', 'Pre-Council', '🎓', true),
(5707, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Most clotting factors are synthesised primarily in the:', '["Kidneys", "Liver", "Spleen", "Bone marrow"]'::jsonb, 1, 'The liver synthesises most clotting factors, which is why severe liver disease commonly causes coagulopathy.', 'Pre-Council', '🎓', true),
(5708, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Vitamin K is essential for the synthesis of which clotting factors?', '["Factors I, V, VIII, XIII", "Factors II, VII, IX, and X", "Only Factor I (fibrinogen)", "Platelets only"]'::jsonb, 1, 'Vitamin K is required for the hepatic synthesis of factors II, VII, IX, and X (and proteins C and S), which is why warfarin (a vitamin K antagonist) is used as an anticoagulant.', 'Pre-Council', '🎓', true),
(5709, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Warfarin exerts its anticoagulant effect primarily by:', '["Directly inhibiting thrombin", "Antagonising vitamin K, reducing synthesis of vitamin K-dependent clotting factors", "Destroying existing clots", "Increasing platelet production"]'::jsonb, 1, 'Warfarin inhibits vitamin K epoxide reductase, reducing hepatic synthesis of vitamin K-dependent clotting factors (II, VII, IX, X).', 'Pre-Council', '🎓', true),
(5710, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Heparin exerts its anticoagulant effect primarily by:', '["Antagonising vitamin K", "Enhancing the activity of antithrombin III to inhibit thrombin and other clotting factors", "Directly lysing existing fibrin clots", "Stimulating platelet aggregation"]'::jsonb, 1, 'Heparin binds and potentiates antithrombin III, which then inactivates thrombin and other clotting factors, providing rapid anticoagulation.', 'Pre-Council', '🎓', true),
(5711, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Haemophilia A results from a deficiency of which clotting factor?', '["Factor VIII", "Factor IX", "Factor XI", "Factor XIII"]'::jsonb, 0, 'Haemophilia A is caused by a deficiency of Factor VIII, an X-linked recessive bleeding disorder.', 'Pre-Council', '🎓', true),
(5712, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Haemophilia B results from a deficiency of which clotting factor?', '["Factor VIII", "Factor IX", "Factor V", "Factor VII"]'::jsonb, 1, 'Haemophilia B (Christmas disease) is caused by a deficiency of Factor IX.', 'Pre-Council', '🎓', true),
(5713, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Disseminated intravascular coagulation (DIC) is characterised by:', '["Isolated excessive clotting with no bleeding risk", "Simultaneous widespread clotting and bleeding due to consumption of clotting factors and platelets", "A deficiency of a single clotting factor only", "Normal fibrinogen and platelet levels"]'::jsonb, 1, 'DIC involves widespread activation of the clotting cascade, consuming platelets and clotting factors faster than they can be replenished, paradoxically causing both microvascular clotting and severe bleeding.', 'Pre-Council', '🎓', true),
(5714, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Fibrinolysis is the process by which the body:', '["Forms new blood clots", "Breaks down and dissolves existing fibrin clots", "Produces red blood cells", "Activates platelets"]'::jsonb, 1, 'Fibrinolysis, primarily via the enzyme plasmin, breaks down fibrin clots once healing has progressed, restoring normal blood flow.', 'Pre-Council', '🎓', true),
(5715, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Plasmin, the key enzyme in fibrinolysis, is formed from its inactive precursor called:', '["Fibrinogen", "Plasminogen", "Prothrombin", "Thrombin"]'::jsonb, 1, 'Plasminogen is converted to active plasmin, which then degrades fibrin clots.', 'Pre-Council', '🎓', true),
(5716, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'D-dimer is a laboratory marker used clinically to indicate:', '["Active platelet production", "Recent clot formation and breakdown (fibrinolysis)", "Vitamin K deficiency", "Red blood cell count"]'::jsonb, 1, 'D-dimer is a fibrin degradation product; elevated levels suggest recent clot formation and breakdown, used to help rule out conditions like DVT or pulmonary embolism.', 'Pre-Council', '🎓', true),
(5717, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Thrombocytopenia refers to:', '["An abnormally high platelet count", "An abnormally low platelet count", "A deficiency of red blood cells", "Excess clotting factors"]'::jsonb, 1, 'Thrombocytopenia is a reduced platelet count, increasing bleeding risk, commonly defined as below 150,000/microlitre.', 'Pre-Council', '🎓', true),
(5718, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'A prolonged prothrombin time (PT/INR) primarily reflects abnormalities in which pathway of coagulation?', '["Intrinsic pathway", "Extrinsic pathway", "Fibrinolytic pathway only", "Platelet function only"]'::jsonb, 1, 'PT/INR reflects the extrinsic and common coagulation pathways, and is used to monitor warfarin therapy.', 'Pre-Council', '🎓', true),
(5719, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'A prolonged activated partial thromboplastin time (aPTT) primarily reflects abnormalities in which pathway of coagulation?', '["Extrinsic pathway", "Intrinsic pathway", "Fibrinolytic pathway only", "Platelet count only"]'::jsonb, 1, 'aPTT reflects the intrinsic and common coagulation pathways, and is used to monitor unfractionated heparin therapy.', 'Pre-Council', '🎓', true),
(5720, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The heart is enclosed within a protective double-layered sac called the:', '["Pleura", "Pericardium", "Peritoneum", "Endocardium"]'::jsonb, 1, 'The pericardium is a fibroserous sac surrounding the heart, providing protection and reducing friction during contraction.', 'Pre-Council', '🎓', true),
(5721, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The innermost layer of the heart wall, lining its chambers, is called the:', '["Epicardium", "Myocardium", "Endocardium", "Pericardium"]'::jsonb, 2, 'The endocardium lines the inner surface of the heart chambers and valves.', 'Pre-Council', '🎓', true),
(5722, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The thick, muscular middle layer of the heart wall responsible for contraction is the:', '["Endocardium", "Myocardium", "Epicardium", "Pericardium"]'::jsonb, 1, 'The myocardium is the cardiac muscle layer responsible for the heart''s pumping action.', 'Pre-Council', '🎓', true),
(5723, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Which heart chamber receives deoxygenated blood from the body via the venae cavae?', '["Left atrium", "Right atrium", "Left ventricle", "Right ventricle"]'::jsonb, 1, 'The right atrium receives deoxygenated systemic venous blood from the superior and inferior venae cavae.', 'Pre-Council', '🎓', true),
(5724, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Which heart chamber pumps oxygenated blood to the entire systemic circulation?', '["Right atrium", "Right ventricle", "Left atrium", "Left ventricle"]'::jsonb, 3, 'The left ventricle, with the thickest myocardial wall, generates the high pressure needed to pump oxygenated blood throughout the systemic circulation.', 'Pre-Council', '🎓', true),
(5725, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The tricuspid valve is located between the:', '["Left atrium and left ventricle", "Right atrium and right ventricle", "Right ventricle and pulmonary artery", "Left ventricle and aorta"]'::jsonb, 1, 'The tricuspid valve, with three cusps, separates the right atrium from the right ventricle.', 'Pre-Council', '🎓', true),
(5726, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The mitral (bicuspid) valve is located between the:', '["Right atrium and right ventricle", "Left atrium and left ventricle", "Left ventricle and aorta", "Right ventricle and pulmonary artery"]'::jsonb, 1, 'The mitral valve, with two cusps, separates the left atrium from the left ventricle.', 'Pre-Council', '🎓', true),
(5727, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The pulmonary valve regulates blood flow from the:', '["Left ventricle into the aorta", "Right ventricle into the pulmonary artery", "Right atrium into the right ventricle", "Left atrium into the left ventricle"]'::jsonb, 1, 'The pulmonary (semilunar) valve controls blood flow from the right ventricle into the pulmonary artery toward the lungs.', 'Pre-Council', '🎓', true),
(5728, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The aortic valve regulates blood flow from the:', '["Right ventricle into the pulmonary artery", "Left ventricle into the aorta", "Left atrium into the left ventricle", "Right atrium into the right ventricle"]'::jsonb, 1, 'The aortic (semilunar) valve controls blood flow from the left ventricle into the aorta toward systemic circulation.', 'Pre-Council', '🎓', true),
(5729, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The heart''s natural pacemaker, which initiates each normal heartbeat, is the:', '["Atrioventricular (AV) node", "Sinoatrial (SA) node", "Bundle of His", "Purkinje fibres"]'::jsonb, 1, 'The SA node, located in the right atrium, spontaneously generates electrical impulses at the fastest intrinsic rate, setting normal heart rhythm.', 'Pre-Council', '🎓', true),
(5730, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The AV node''s primary function in the cardiac conduction system is to:', '["Generate the primary pacemaker impulse", "Briefly delay the electrical impulse, allowing the atria to fully contract before ventricular contraction", "Directly cause ventricular contraction without delay", "Regulate coronary blood flow"]'::jsonb, 1, 'The AV node introduces a brief delay in impulse conduction, ensuring atrial contraction completes and fills the ventricles before ventricular systole begins.', 'Pre-Council', '🎓', true),
(5731, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Electrical impulses travel from the AV node to the ventricles via the:', '["SA node", "Bundle of His and Purkinje fibres", "Coronary sinus", "Pulmonary veins"]'::jsonb, 1, 'After the AV node, impulses travel through the Bundle of His, then the left and right bundle branches, and finally the Purkinje fibres, causing coordinated ventricular contraction.', 'Pre-Council', '🎓', true),
(5732, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Coronary arteries, which supply blood to the heart muscle itself, arise from the:', '["Pulmonary artery", "Base of the aorta, just above the aortic valve", "Superior vena cava", "Right atrium"]'::jsonb, 1, 'The left and right coronary arteries originate from the aortic root just above the aortic valve cusps, delivering oxygenated blood to the myocardium.', 'Pre-Council', '🎓', true),
(5733, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Cardiac output is defined as:', '["Heart rate alone", "The volume of blood ejected by the heart per minute (heart rate x stroke volume)", "Stroke volume alone", "Blood pressure"]'::jsonb, 1, 'Cardiac output equals heart rate multiplied by stroke volume, representing the total volume of blood pumped by the heart each minute.', 'Pre-Council', '🎓', true),
(5734, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Stroke volume refers to:', '["The total blood volume in the body", "The volume of blood ejected by the ventricle with each heartbeat", "Heart rate per minute", "Total peripheral resistance"]'::jsonb, 1, 'Stroke volume is the amount of blood ejected from a ventricle during a single contraction, normally about 60-100 mL.', 'Pre-Council', '🎓', true),
(5735, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Preload refers to:', '["The resistance the heart must pump against", "The degree of ventricular stretch/filling before contraction", "The heart rate", "Coronary artery resistance"]'::jsonb, 1, 'Preload is the volume of blood filling the ventricle at the end of diastole, which stretches the myocardial fibres before contraction (related to the Frank-Starling mechanism).', 'Pre-Council', '🎓', true),
(5736, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Afterload refers to:', '["The volume of blood filling the ventricle before contraction", "The resistance the ventricle must overcome to eject blood", "Heart rate", "Venous return"]'::jsonb, 1, 'Afterload is the resistance (largely determined by systemic vascular resistance and arterial pressure) that the ventricle must overcome to eject blood during systole.', 'Pre-Council', '🎓', true),
(5737, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'According to the Frank-Starling law of the heart, increased ventricular filling (preload) generally results in:', '["Decreased force of contraction", "Increased force of contraction, up to a physiological limit", "No change in contraction force", "Immediate cardiac failure"]'::jsonb, 1, 'The Frank-Starling mechanism describes how greater stretch of cardiac muscle fibres from increased preload produces a stronger contraction, matching cardiac output to venous return, within physiological limits.', 'Pre-Council', '🎓', true),
(5738, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Arteries are structurally distinguished from veins primarily by having:', '["Thinner walls and valves", "Thicker, more muscular walls to withstand higher pressure", "No smooth muscle", "Larger overall diameter"]'::jsonb, 1, 'Arteries have thicker, more muscular and elastic walls to withstand and help propel blood under higher pressure from the heart.', 'Pre-Council', '🎓', true),
(5739, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Veins contain valves primarily to:', '["Increase blood pressure", "Prevent backflow of blood, aiding venous return against gravity", "Filter blood", "Regulate heart rate"]'::jsonb, 1, 'Venous valves prevent retrograde blood flow, helping return blood to the heart, particularly important in the lower limbs against gravity.', 'Pre-Council', '🎓', true),
(5740, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Capillaries are the primary site of:', '["Blood storage", "Exchange of gases, nutrients, and waste between blood and tissue", "Blood clot formation", "Blood pressure regulation"]'::jsonb, 1, 'The thin, single-cell-layer walls of capillaries allow efficient diffusion of oxygen, nutrients, carbon dioxide, and waste products between blood and surrounding tissue.', 'Pre-Council', '🎓', true),
(5741, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The tunica media, a key layer of arterial walls, is composed mainly of:', '["Endothelium", "Smooth muscle and elastic fibres", "Connective tissue only", "Epithelium"]'::jsonb, 1, 'The tunica media contains smooth muscle and elastic fibres, allowing arteries to constrict, dilate, and withstand pulsatile pressure.', 'Pre-Council', '🎓', true),
(5742, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The innermost layer of a blood vessel, in direct contact with blood, is the:', '["Tunica externa", "Tunica media", "Tunica intima (endothelium)", "Adventitia"]'::jsonb, 2, 'The tunica intima, lined by endothelium, is the innermost vessel layer in direct contact with flowing blood.', 'Pre-Council', '🎓', true),
(5743, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Arterioles play a key role in regulating blood pressure primarily because they:', '["Have the largest total cross-sectional area", "Are the primary site of resistance to blood flow, adjustable via smooth muscle tone", "Contain valves like veins", "Store the majority of blood volume"]'::jsonb, 1, 'Arterioles, with their relatively narrow lumen and abundant smooth muscle, are the principal site of vascular resistance and blood pressure regulation.', 'Pre-Council', '🎓', true),
(5744, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The systemic circulation carries blood from the:', '["Right ventricle to the lungs and back to the left atrium", "Left ventricle to the body and back to the right atrium", "Right atrium directly to the left atrium", "Lungs directly to the body"]'::jsonb, 1, 'Systemic circulation carries oxygenated blood from the left ventricle to body tissues, returning deoxygenated blood to the right atrium.', 'Pre-Council', '🎓', true),
(5745, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The pulmonary circulation carries blood from the:', '["Left ventricle to the body", "Right ventricle to the lungs and back to the left atrium", "Right atrium to the body", "Aorta to the lungs"]'::jsonb, 1, 'Pulmonary circulation carries deoxygenated blood from the right ventricle to the lungs for gas exchange, returning oxygenated blood to the left atrium.', 'Pre-Council', '🎓', true),
(5746, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The lymphatic system functions primarily to:', '["Transport oxygen to tissues", "Return excess interstitial fluid to the bloodstream and support immune function", "Regulate heart rate", "Produce red blood cells"]'::jsonb, 1, 'The lymphatic system drains excess interstitial fluid back into venous circulation and plays a key role in immune surveillance and response.', 'Pre-Council', '🎓', true),
(5747, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Lymph is derived from:', '["Blood plasma that has leaked into interstitial spaces and is collected by lymphatic vessels", "Red blood cells only", "Bile", "Cerebrospinal fluid"]'::jsonb, 0, 'Lymph originates as interstitial fluid (filtered plasma) that lymphatic capillaries collect and return toward the venous system.', 'Pre-Council', '🎓', true),
(5748, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Unlike blood vessels, the lymphatic system lacks a central pump; lymph flow relies mainly on:', '["Cardiac contraction", "Skeletal muscle contraction, valves, and smooth muscle in vessel walls", "Gravity alone", "Blood pressure directly"]'::jsonb, 1, 'Lymph movement depends on skeletal muscle contraction (''milking'' action), one-way valves preventing backflow, and rhythmic contraction of lymphatic vessel walls.', 'Pre-Council', '🎓', true),
(5749, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Lymph nodes function primarily to:', '["Produce red blood cells", "Filter lymph and house immune cells that respond to pathogens", "Regulate blood pressure", "Store bile"]'::jsonb, 1, 'Lymph nodes filter lymph fluid and contain lymphocytes and macrophages that detect and respond to pathogens or abnormal cells.', 'Pre-Council', '🎓', true),
(5750, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Swollen (enlarged) lymph nodes most commonly indicate:', '["Normal anatomical variation with no clinical significance", "An active immune response to infection, inflammation, or malignancy", "Dehydration", "Low blood pressure"]'::jsonb, 1, 'Lymphadenopathy typically reflects increased immune activity within the node in response to infection, inflammation, or, less commonly, malignancy.', 'Pre-Council', '🎓', true),
(5751, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The largest lymphatic vessel, which drains lymph from most of the body into the venous system, is the:', '["Right lymphatic duct", "Thoracic duct", "Cisterna chyli", "Splenic vein"]'::jsonb, 1, 'The thoracic duct is the largest lymphatic vessel, draining lymph from the lower body, left arm, and left side of the head/neck into the left subclavian vein.', 'Pre-Council', '🎓', true),
(5752, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The right lymphatic duct drains lymph from:', '["The entire body", "The right upper quadrant of the body (right arm, right side of head/neck/thorax)", "Only the legs", "The abdominal organs only"]'::jsonb, 1, 'The right lymphatic duct drains lymph from the right upper body region into the right subclavian vein, a smaller drainage area than the thoracic duct.', 'Pre-Council', '🎓', true),
(5753, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'The spleen, part of the lymphatic system, primarily functions to:', '["Produce bile", "Filter blood, remove old/damaged red blood cells, and support immune function", "Regulate blood glucose", "Produce clotting factors"]'::jsonb, 1, 'The spleen filters blood, removing senescent or damaged erythrocytes, stores platelets, and contributes to immune responses.', 'Pre-Council', '🎓', true),
(5754, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Lymphatic capillaries differ from blood capillaries in that lymphatic capillaries:', '["Are less permeable and have a continuous basement membrane", "Are more permeable, with overlapping endothelial cells acting as one-way flaps allowing fluid entry but not exit", "Contain red blood cells normally", "Have thick muscular walls"]'::jsonb, 1, 'Lymphatic capillaries have loosely overlapping endothelial cells that act as one-way valves, allowing interstitial fluid, proteins, and even large particles to enter but not leave the vessel.', 'Pre-Council', '🎓', true),
(5755, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Lymphoedema results from:', '["Excess red blood cell production", "Impaired lymphatic drainage causing fluid accumulation in tissue", "Increased venous return", "Low blood pressure"]'::jsonb, 1, 'Lymphoedema occurs when lymphatic vessels are damaged, obstructed, or removed (e.g. after lymph node dissection), impairing fluid drainage and causing tissue swelling.', 'Pre-Council', '🎓', true),
(5756, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Peyer''s patches, a component of lymphatic tissue, are located primarily in the:', '["Skin", "Small intestine (ileum)", "Lungs", "Kidneys"]'::jsonb, 1, 'Peyer''s patches are aggregates of lymphoid tissue in the ileum that monitor intestinal bacterial populations and prevent pathogen growth.', 'Pre-Council', '🎓', true),
(5757, 'Cardiovascular System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit II', 'Which lymphoid organ is responsible for the maturation of T lymphocytes?', '["Spleen", "Thymus", "Lymph nodes", "Bone marrow"]'::jsonb, 1, 'The thymus, most active in childhood, is where immature T lymphocytes mature and undergo selection before entering circulation.', 'Pre-Council', '🎓', true);
